// === BASIC SUM AND AVERAGE ===
=SUM(B2:B10)           // Adds all values in B2 through B10
=AVERAGE(B2:B10)        // Calculates the mean of B2:B10
=COUNT(B2:B10)          // Counts only numeric cells
=COUNTA(A2:A10)         // Counts all non-empty cells (including text)

// === CONDITIONAL LOGIC ===
=IF(C2>5000,"OVER BUDGET","On Track")
// If the value in C2 exceeds 5000, show "OVER BUDGET", otherwise "On Track"

=IF(AND(C2>5000, D2="Active"),"URGENT REVIEW","OK")
// Flag only active projects that are also over budget

=IFS(C2<1000,"Low", C2<5000,"Medium", C2>=5000,"High")
// Assign a cost category based on the value in C2

// === LOOKUP FORMULAS ===
=VLOOKUP(A2, RateTable!A:B, 2, FALSE)
// Look up the value in A2 in the first column of RateTable,
// return the matching value from column 2. FALSE = exact match.

=XLOOKUP(A2, RateTable!A:A, RateTable!B:B, "Not Found")
// Modern replacement for VLOOKUP — no column number needed,
// returns "Not Found" if no match exists.

// === DATE CALCULATIONS ===
=TODAY()                         // Returns today's date
=DATEDIF(B2, TODAY(), "D")       // Days between date in B2 and today
=NETWORKDAYS(B2, C2)             // Working days between two dates (excludes weekends)

// === TEXT FUNCTIONS ===
=CONCATENATE(A2," ",B2)          // Joins first name and last name with a space
=TRIM(A2)                        // Removes extra spaces from imported data
=UPPER(A2)                       // Converts text to uppercase

// === SUMIF — One Condition ===
// Syntax: =SUMIF(range, criteria, sum_range)

=SUMIF(B2:B20, "Leo", D2:D20)
// Adds all values in D2:D20 where the matching cell in B2:B20 equals "Leo"
// Use: total hours logged by Leo across all projects

// === SUMIFS — Multiple Conditions ===
// Syntax: =SUMIFS(sum_range, criteria_range1, criteria1, criteria_range2, criteria2, ...)

=SUMIFS(D2:D20, B2:B20, "Leo", C2:C20, "Project Alpha")
// Adds hours in D2:D20 where team member is Leo AND project is Project Alpha
// Use: Leo's total hours on Project Alpha specifically

// === AVERAGEIF — Conditional Average ===
=AVERAGEIF(C2:C20, "Project Alpha", D2:D20)
// Average hours per entry where project is Project Alpha

// === COUNTIF — Count Matching Cells ===
=COUNTIF(B2:B20, "Sparky")
// How many rows have Sparky as the team member?

